#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n; if(!(cin>>n)) return 0; // length, not needed
    string s; cin>>s;
    vector<char> st;
    unordered_map<char,char> mp{{')','('},{']','['},{'}','{'}};
    bool ok=true;
    for(char c: s){
        if(c=='('||c=='['||c=='{') st.push_back(c);
        else{
            if(st.empty()|| st.back()!=mp[c]){ ok=false; break; }
            st.pop_back();
        }
    }
    if(!st.empty()) ok=false;
    cout<<(ok?"true":"false");
    return 0;
}
